36	namespace ngp {
37	
38	extern std::atomic<size_t> g_total_n_bytes_allocated;
39	
40	void CudaSurface2D::free() {
41		if (m_surface) {
42			cudaDestroySurfaceObject(m_surface);
43		}
44		m_surface = 0;
45		if (m_array) {
46			cudaFreeArray(m_array);
47			g_total_n_bytes_allocated -= product(m_size) * sizeof(float) * m_n_channels;
48		}
49		m_array = nullptr;
50		m_size = ivec2(0);
51		m_n_channels = 0;
52	}
53	
54	void CudaSurface2D::resize(const ivec2& size, int n_channels) {
55		if (size == m_size && n_channels == m_n_channels) {
56			return;
57		}
58	
59		free();
60	
61		cudaChannelFormatDesc desc;
62		switch (n_channels) {
63			case 1: desc = cudaCreateChannelDesc<float>(); break;
64			case 2: desc = cudaCreateChannelDesc<float2>(); break;
65			case 3: desc = cudaCreateChannelDesc<float3>(); break;
66			case 4: desc = cudaCreateChannelDesc<float4>(); break;
67			default: throw std::runtime_error{fmt::format("CudaSurface2D: unsupported number of channels {}", n_channels)};
68		}
69		CUDA_CHECK_THROW(cudaMallocArray(&m_array, &desc, size.x, size.y, cudaArraySurfaceLoadStore));
70	
71		g_total_n_bytes_allocated += product(m_size) * sizeof(float) * n_channels;
72	
73		struct cudaResourceDesc resource_desc;
74		memset(&resource_desc, 0, sizeof(resource_desc));
75		resource_desc.resType = cudaResourceTypeArray;
76		resource_desc.res.array.array = m_array;
77		CUDA_CHECK_THROW(cudaCreateSurfaceObject(&m_surface, &resource_desc));
78	
79		m_size = size;
80		m_n_channels = n_channels;
81	}
82	
83	#ifdef NGP_GUI
84	GLTexture::~GLTexture() {
85		m_cuda_mapping.reset();
86		if (m_texture_id) {
87			glDeleteTextures(1, &m_texture_id);
88		}
89	}
90	
91	GLuint GLTexture::texture() {
92		if (!m_texture_id) {
93			glGenTextures(1, &m_texture_id);
94		}
95	
96		return m_texture_id;
97	}
98	
99	cudaSurfaceObject_t GLTexture::surface() {
100		if (!m_cuda_mapping) {
101			m_cuda_mapping = std::make_unique<CUDAMapping>(texture(), m_size, m_n_channels);
102		}
103		return m_cuda_mapping->surface();
104	}
105	
