153	void GLTexture::resize(const ivec2& new_size, int n_channels, bool is_8bit) {
154		if (m_size == new_size && m_n_channels == n_channels && m_is_8bit == is_8bit) {
155			return;
156		}
157	
158		if (m_texture_id) {
159			m_cuda_mapping.reset();
160			glDeleteTextures(1, &m_texture_id);
161			m_texture_id = 0;
162		}
163	
164		glGenTextures(1, &m_texture_id);
165		glBindTexture(GL_TEXTURE_2D, m_texture_id);
166	
167		switch (n_channels) {
168			case 1: m_internal_format = is_8bit ? GL_R8    : GL_R32F;    m_format = GL_RED;  break;
169			case 2: m_internal_format = is_8bit ? GL_RG8   : GL_RG32F;   m_format = GL_RG;   break;
170			case 3: m_internal_format = is_8bit ? GL_RGB8  : GL_RGB32F;  m_format = GL_RGB;  break;
171			case 4: m_internal_format = is_8bit ? GL_RGBA8 : GL_RGBA32F; m_format = GL_RGBA; break;
172			default: throw std::runtime_error{fmt::format("GLTexture: unsupported number of channels {}", n_channels)};
173		}
174		m_is_8bit = is_8bit;
175		m_size = new_size;
176		m_n_channels = n_channels;
177	
178		glTexImage2D(GL_TEXTURE_2D, 0, m_internal_format, new_size.x, new_size.y, 0, m_format, is_8bit ? GL_UNSIGNED_BYTE : GL_FLOAT, nullptr);
179		glTexParameteri(GL_TEXTURE_2D, GL_TEXTURE_WRAP_S, GL_CLAMP_TO_EDGE);
180		glTexParameteri(GL_TEXTURE_2D, GL_TEXTURE_WRAP_T, GL_CLAMP_TO_EDGE);
181		glTexParameteri(GL_TEXTURE_2D, GL_TEXTURE_MAG_FILTER, GL_NEAREST);
182		glTexParameteri(GL_TEXTURE_2D, GL_TEXTURE_MIN_FILTER, GL_NEAREST);
183	}
