185	GLTexture::CUDAMapping::CUDAMapping(GLuint texture_id, const ivec2& size, int n_channels) : m_size{size}, m_n_channels{n_channels} {
186		static bool s_is_cuda_interop_supported = !is_wsl();
187		if (s_is_cuda_interop_supported) {
188			cudaError_t err = cudaGraphicsGLRegisterImage(&m_graphics_resource, texture_id, GL_TEXTURE_2D, cudaGraphicsRegisterFlagsSurfaceLoadStore);
189			if (err != cudaSuccess) {
190				s_is_cuda_interop_supported = false;
191				cudaGetLastError(); // Reset error
192			}
193		}
194	
195		if (!s_is_cuda_interop_supported) {
196			// falling back to a regular cuda surface + CPU copy of data
197			m_cuda_surface = std::make_unique<CudaSurface2D>();
198			m_cuda_surface->resize(size, n_channels);
199			m_data_cpu.resize(product(m_size) * n_channels);
200			return;
201		}
202	
203		CUDA_CHECK_THROW(cudaGraphicsMapResources(1, &m_graphics_resource));
204		CUDA_CHECK_THROW(cudaGraphicsSubResourceGetMappedArray(&m_mapped_array, m_graphics_resource, 0, 0));
205	
206		struct cudaResourceDesc resource_desc;
207		memset(&resource_desc, 0, sizeof(resource_desc));
208		resource_desc.resType = cudaResourceTypeArray;
209		resource_desc.res.array.array = m_mapped_array;
210	
211		CUDA_CHECK_THROW(cudaCreateSurfaceObject(&m_surface, &resource_desc));
212	}
