228	__global__ void accumulate_kernel(ivec2 resolution, vec4* frame_buffer, vec4* accumulate_buffer, float sample_count, EColorSpace color_space) {
229		uint32_t x = threadIdx.x + blockDim.x * blockIdx.x;
230		uint32_t y = threadIdx.y + blockDim.y * blockIdx.y;
231	
232		if (x >= resolution.x || y >= resolution.y) {
233			return;
234		}
235	
236		uint32_t idx = x + resolution.x * y;
237	
238		vec4 color = frame_buffer[idx];
239		vec4 tmp = accumulate_buffer[idx];
240	
241		switch (color_space) {
242			case EColorSpace::VisPosNeg:
243				{
244					float val = color.x - color.y;
245					float tmp_val = tmp.x - tmp.y;
246	
247					tmp_val = (tmp_val * sample_count + val) / (sample_count+1);
248	
249					tmp.x = fmaxf(tmp_val, 0.0f);
250					tmp.y = fmaxf(-tmp_val, 0.0f);
251					break;
252				}
253			case EColorSpace::SRGB:
254				color.rgb() = linear_to_srgb(color.rgb());
255				// fallthrough is intended!
256			case EColorSpace::Linear:
257				tmp.rgb() = (tmp.rgb() * sample_count + color.rgb()) / (sample_count+1); break;
258		}
259	
260		tmp.a = (tmp.a * sample_count + color.a) / (sample_count+1);
261		accumulate_buffer[idx] = tmp;
262	}
263	
264	__device__ vec3 tonemap(vec3 x, ETonemapCurve curve) {
265		if (curve == ETonemapCurve::Identity) {
266			return x;
267		}
268	
269		x = max(x, vec3(0.0f));
270	
271		float k0, k1, k2, k3, k4, k5;
272		if (curve == ETonemapCurve::ACES) {
273			// Source:  ACES approximation : https://knarkowicz.wordpress.com/2016/01/06/aces-filmic-tone-mapping-curve/
274			// Include pre - exposure cancelation in constants
275			k0 = 0.6f * 0.6f * 2.51f;
276			k1 = 0.6f * 0.03f;
277			k2 = 0.0f;
278			k3 = 0.6f * 0.6f * 2.43f;
279			k4 = 0.6f * 0.59f;
280			k5 = 0.14f;
281		} else if (curve == ETonemapCurve::Hable) {
282			// Source: https://64.github.io/tonemapping/
283			const float A = 0.15f;
284			const float B = 0.50f;
285			const float C = 0.10f;
286			const float D = 0.20f;
287			const float E = 0.02f;
288			const float F = 0.30f;
289			k0 = A * F - A * E;
290			k1 = C * B * F - B * E;
291			k2 = 0.0f;
292			k3 = A * F;
293			k4 = B * F;
294			k5 = D * F * F;
295	
296			const float W = 11.2f;
297			const float nom = k0 * (W*W) + k1 * W + k2;
298			const float denom = k3 * (W*W) + k4 * W + k5;
299			const float white_scale = denom / nom;
300	
301			// Include white scale and exposure bias in rational polynomial coefficients
302			k0 = 4.0f * k0 * white_scale;
303			k1 = 2.0f * k1 * white_scale;
304			k2 = k2 * white_scale;
305			k3 = 4.0f * k3;
306			k4 = 2.0f * k4;
307		} else { //if (curve == ETonemapCurve::Reinhard)
308			const vec3 luminance_coefficients = {0.2126f, 0.7152f, 0.0722f};
309			float Y = dot(luminance_coefficients, x);
310	
311			return x * (1.f / (Y + 1.0f));
312		}
313	
314		vec3 color_sq = x * x;
315		vec3 nom = color_sq * k0 + k1 * x + k2;
316		vec3 denom = k3 * color_sq + k4 * x + k5;
317	
318		vec3 tonemapped_color = nom / denom;
319	
320		return tonemapped_color;
321	}
322	
323	__device__ vec3 tonemap(vec3 col, const vec3& exposure, ETonemapCurve tonemap_curve, EColorSpace color_space, EColorSpace output_color_space) {
324		// Conversion to output by
325		// 1. converting to linear. (VisPosNeg is treated as linear red/green)
326		if (color_space == EColorSpace::SRGB) {
327			col = srgb_to_linear(col);
328		}
329	
330		// 2. applying exposure in linear space
331		col *= pow(vec3(2.0f), exposure);
332	
333		// 3. tonemapping in linear space according to the specified curve
334		col = tonemap(col, tonemap_curve);
335	
336		// 4. converting to output color space.
337		if (output_color_space == EColorSpace::SRGB) {
338			col = linear_to_srgb(col);
339		}
340	
341		return col;
342	}
