344	__global__ void overlay_image_kernel(
345		ivec2 resolution,
346		float alpha,
347		vec3 exposure,
348		vec4 background_color,
349		const void* __restrict__ image,
350		EImageDataType image_data_type,
351		ivec2 image_resolution,
352		ETonemapCurve tonemap_curve,
353		EColorSpace color_space,
354		EColorSpace output_color_space,
355		int fov_axis,
356		float zoom,
357		vec2 screen_center,
358		cudaSurfaceObject_t surface
359	) {
360		uint32_t x = threadIdx.x + blockDim.x * blockIdx.x;
361		uint32_t y = threadIdx.y + blockDim.y * blockIdx.y;
362	
363		if (x >= resolution.x || y >= resolution.y) {
364			return;
365		}
366	
367		float scale = image_resolution[fov_axis] / float(resolution[fov_axis]);
368	
369		float fx = x+0.5f;
370		float fy = y+0.5f;
371	
372		fx -= resolution.x * 0.5f; fx /= zoom; fx += screen_center.x * resolution.x;
373		fy -= resolution.y * 0.5f; fy /= zoom; fy += screen_center.y * resolution.y;
374	
375		float u = (fx - resolution.x * 0.5f) * scale  + image_resolution.x * 0.5f;
376		float v = (fy - resolution.y * 0.5f) * scale  + image_resolution.y * 0.5f;
377	
378		int srcx = floorf(u);
379		int srcy = floorf(v);
380	
381		vec4 val;
382		if (srcx >= image_resolution.x || srcy >= image_resolution.y || srcx < 0 || srcy < 0) {
383			val = vec4(0.0f);
384		} else {
385			val = read_rgba(ivec2{srcx, srcy}, image_resolution, image, image_data_type);
386		}
387	
388		vec4 color = {val[0], val[1], val[2], val[3]};
389	
390		// The background color is represented in SRGB, so convert
391		// to linear if that's not the space in which we're rendering.
392		if (color_space != EColorSpace::SRGB) {
393			background_color.xyz() = srgb_to_linear(background_color.xyz());
394		} else {
395			if (color.a > 0) {
396				color.rgb() = linear_to_srgb(color.rgb() / color.a) * color.a;
397			} else {
398				color.rgb() = vec3(0.0f);
399			}
400		}
401	
402		float weight = (1 - color.a) * background_color.a;
403		color.rgb() += background_color.rgb() * weight;
404		color.a += weight;
405	
406		color.rgb() = tonemap(color.rgb(), exposure, tonemap_curve, color_space, output_color_space);
407	
408		vec4 prev_color;
409		surf2Dread((float4*)&prev_color, surface, x * sizeof(float4), y);
410		color = color * alpha + prev_color * (1.f-alpha);
411		surf2Dwrite(to_float4(color), surface, x * sizeof(float4), y);
412	}
