462	__device__ vec3 colormap_viridis(float x) {
463		const vec3 c0 = vec3{0.2777273272234177f, 0.005407344544966578f, 0.3340998053353061f};
464		const vec3 c1 = vec3{0.1050930431085774f, 1.404613529898575f, 1.384590162594685f};
465		const vec3 c2 = vec3{-0.3308618287255563f, 0.214847559468213f, 0.09509516302823659f};
466		const vec3 c3 = vec3{-4.634230498983486f, -5.799100973351585f, -19.33244095627987f};
467		const vec3 c4 = vec3{6.228269936347081f, 14.17993336680509f, 56.69055260068105f};
468		const vec3 c5 = vec3{4.776384997670288f, -13.74514537774601f, -65.35303263337234f};
469		const vec3 c6 = vec3{-5.435455855934631f, 4.645852612178535f, 26.3124352495832f};
470		x = __saturatef(x);
471		return (c0+x*(c1+x*(c2+x*(c3+x*(c4+x*(c5+x*c6))))));
472	}
