474	__global__ void overlay_false_color_kernel(ivec2 resolution, ivec2 training_resolution, bool to_srgb, int fov_axis, cudaSurfaceObject_t surface, const float *error_map, ivec2 error_map_resolution, const float *average, float brightness, bool viridis) {
475		uint32_t x = threadIdx.x + blockDim.x * blockIdx.x;
476		uint32_t y = threadIdx.y + blockDim.y * blockIdx.y;
477	
478		if (x >= resolution.x || y >= resolution.y) {
479			return;
480		}
481	
482		float error_map_scale = brightness/(0.0000001f+average[0]); // average maps to 1/16th
483	
484		float scale = training_resolution[fov_axis] / float(resolution[fov_axis]);
485		float u = (x+0.5f-resolution.x*0.5f) * scale + training_resolution.x*0.5f;
486		float v = (y+0.5f-resolution.y*0.5f) * scale + training_resolution.y*0.5f;
487		int srcx = floor(u * error_map_resolution.x / float(max(1.f, (float)training_resolution.x)));
488		int srcy = floor(v * error_map_resolution.y / float(max(1.f, (float)training_resolution.y)));
489	
490		uint32_t srcidx = srcx + error_map_resolution.x * srcy;
491	
492		if (srcx >= error_map_resolution.x || srcy >= error_map_resolution.y || srcx<0 || srcy<0) {
493			return;
494		}
495	
496		float err = error_map[srcidx] * error_map_scale;
497		if (viridis) {
498			err *= 1.f / (1.f+err);
499		}
500		vec4 color;
501		surf2Dread((float4*)&color, surface, x * sizeof(float4), y);
502		vec3 c = viridis ? colormap_viridis(err) : colormap_turbo(err);
503		float grey = color.x * 0.2126f + color.y * 0.7152f + color.z * 0.0722f;
504		color.x = grey*__saturatef(c.x);
505		color.y = grey*__saturatef(c.y);
506		color.z = grey*__saturatef(c.z);
507	
508		surf2Dwrite(to_float4(color), surface, x * sizeof(float4), y);
509	}
