511	__global__ void tonemap_kernel(ivec2 resolution, float exposure, vec4 background_color, vec4* accumulate_buffer, EColorSpace color_space, EColorSpace output_color_space, ETonemapCurve tonemap_curve, bool clamp_output_color, bool unmultiply_alpha, cudaSurfaceObject_t surface) {
512		uint32_t x = threadIdx.x + blockDim.x * blockIdx.x;
513		uint32_t y = threadIdx.y + blockDim.y * blockIdx.y;
514	
515		if (x >= resolution.x || y >= resolution.y) {
516			return;
517		}
518	
519		uint32_t idx = x + resolution.x * y;
520	
521		// The background color is represented in SRGB, so convert
522		// to linear if that's not the space in which we're rendering.
523		if (color_space != EColorSpace::SRGB) {
524			background_color.rgb() = srgb_to_linear(background_color.rgb());
525		}
526	
527		vec4 color = accumulate_buffer[idx];
528		float weight = (1 - color.a) * background_color.a;
529		color.rgb() += background_color.rgb() * weight;
530		color.a += weight;
531	
532		color.rgb() = tonemap(color.rgb(), vec3(exposure), tonemap_curve, color_space, output_color_space);
533	
534		if (unmultiply_alpha && color.a > 0.0f) {
535			color.rgb() = color.rgb() / color.a;
536		}
537	
538		if (clamp_output_color) {
539			color = clamp(color, vec4(0.0f), vec4(1.0f));
540		}
541	
542		surf2Dwrite(to_float4(color), surface, x * sizeof(float4), y);
543	}
