545	__global__ void dlss_splat_kernel(
546		ivec2 resolution,
547		cudaSurfaceObject_t dlss_surface,
548		cudaSurfaceObject_t surface
549	) {
550		uint32_t x = threadIdx.x + blockDim.x * blockIdx.x;
551		uint32_t y = threadIdx.y + blockDim.y * blockIdx.y;
552	
553		if (x >= resolution.x || y >= resolution.y) {
554			return;
555		}
556	
557		float4 color;
558		surf2Dread(&color, dlss_surface, x * sizeof(float4), y);
559	
560		// DLSS operates on non-premultiplied alpha, so multiply it back in
561		color.x *= color.w;
562		color.y *= color.w;
563		color.z *= color.w;
564		surf2Dwrite(color, surface, x * sizeof(float4), y);
565	}
