591	void CudaRenderBuffer::resize(const ivec2& res) {
592		m_in_resolution = res;
593		m_frame_buffer.enlarge(res.x * res.y);
594		m_depth_buffer.enlarge(res.x * res.y);
595		if (m_depth_target) {
596			m_depth_target->resize(res, 1);
597		}
598		m_accumulate_buffer.enlarge(res.x * res.y);
599	
600		ivec2 out_res = m_dlss ? m_dlss->out_resolution() : res;
601		auto prev_out_res = out_resolution();
602		m_rgba_target->resize(out_res, 4);
603	
604		if (out_resolution() != prev_out_res) {
605			reset_accumulation();
606		}
607	}
608	
609	void CudaRenderBuffer::clear_frame(cudaStream_t stream) {
610		view().clear(stream);
611	}
612	
613	void CudaRenderBuffer::accumulate(float exposure, cudaStream_t stream) {
614		ivec2 res = in_resolution();
615	
616		uint32_t accum_spp = m_dlss ? 0 : m_spp;
617	
618		if (accum_spp == 0) {
619			CUDA_CHECK_THROW(cudaMemsetAsync(m_accumulate_buffer.data(), 0, m_accumulate_buffer.bytes(), stream));
620		}
621	
622		const dim3 threads = { 16, 8, 1 };
623		const dim3 blocks = { div_round_up((uint32_t)res.x, threads.x), div_round_up((uint32_t)res.y, threads.y), 1 };
624		accumulate_kernel<<<blocks, threads, 0, stream>>>(
625			res,
626			frame_buffer(),
627			accumulate_buffer(),
628			(float)accum_spp,
629			m_color_space
630		);
631	
632		++m_spp;
633	}
634	
635	void CudaRenderBuffer::tonemap(float exposure, const vec4& background_color, EColorSpace output_color_space, float znear, float zfar, bool snap_to_pixel_centers, cudaStream_t stream) {
636		assert(m_dlss || out_resolution() == in_resolution());
637	
638		auto res = in_resolution();
639		const dim3 threads = { 16, 8, 1 };
640		const dim3 blocks = { div_round_up((uint32_t)res.x, threads.x), div_round_up((uint32_t)res.y, threads.y), 1 };
641		tonemap_kernel<<<blocks, threads, 0, stream>>>(
642			res,
643			exposure,
644			background_color,
645			accumulate_buffer(),
646			m_color_space,
647			output_color_space,
648			m_tonemap_curve,
649			m_dlss && output_color_space == EColorSpace::SRGB,
650			(bool)m_dlss, // DLSS seems to perform best with non-premultiplied alpha (probably trained on such data)
651			m_dlss ? m_dlss->frame() : surface()
652		);
653	
654		if (m_dlss) {
655			assert(out_resolution() == m_dlss->out_resolution());
656	
657			assert(m_spp >= 1);
658			uint32_t sample_index = m_spp - 1;
659	
660			m_dlss->run(
661				res,
662				output_color_space == EColorSpace::Linear, /* HDR mode */
663				m_dlss_sharpening,
664				vec2(0.5f) - ld_random_pixel_offset(snap_to_pixel_centers ? 0 : sample_index), /* jitter offset in [-0.5, 0.5] */
665				sample_index == 0 /* reset history */
666			);
667	
668			auto out_res = out_resolution();
669			const dim3 out_blocks = { div_round_up((uint32_t)out_res.x, threads.x), div_round_up((uint32_t)out_res.y, threads.y), 1 };
670			dlss_splat_kernel<<<out_blocks, threads, 0, stream>>>(out_res, m_dlss->output(), surface());
671		}
672	
673		if (m_depth_target) {
674			depth_splat_kernel<<<blocks, threads, 0, stream>>>(res, znear, zfar, depth_buffer(), m_depth_target->surface());
675		}
676	}
677	
678	void CudaRenderBuffer::overlay_image(
679		float alpha,
680		const vec3& exposure,
681		const vec4& background_color,
682		EColorSpace output_color_space,
683		const void* __restrict__ image,
684		EImageDataType image_data_type,
685		const ivec2& image_resolution,
