712	void CudaRenderBuffer::overlay_depth(
713		float alpha,
714		const float* __restrict__ depth,
715		float depth_scale,
716		const ivec2& image_resolution,
717		int fov_axis,
718		float zoom,
719		const vec2& screen_center,
