738	void CudaRenderBuffer::overlay_false_color(ivec2 training_resolution, bool to_srgb, int fov_axis, cudaStream_t stream, const float* error_map, ivec2 error_map_resolution, const float* average, float brightness, bool viridis) {
739		auto res = out_resolution();
