142	struct FoveationPiecewiseQuadratic {
143		FoveationPiecewiseQuadratic() = default;
144		NGP_HOST_DEVICE FoveationPiecewiseQuadratic(float center_pixel_steepness, float center_inverse_piecewise_y, float center_radius) {
145			float center_inverse_radius = center_radius * center_pixel_steepness;
146			float left_inverse_piecewise_switch = center_inverse_piecewise_y - center_inverse_radius;
147			float right_inverse_piecewise_switch = center_inverse_piecewise_y + center_inverse_radius;
148	
149			if (left_inverse_piecewise_switch < 0) {
150				left_inverse_piecewise_switch = 0.0f;
151			}
152	
153			if (right_inverse_piecewise_switch > 1) {
154				right_inverse_piecewise_switch = 1.0f;
155			}
156	
157			float am = center_pixel_steepness;
158			float d = (right_inverse_piecewise_switch - left_inverse_piecewise_switch) / center_pixel_steepness / 2;
159	
160			// binary search for l,r,bm since analytical is very complex
161			float bm;
162			float m_min = 0.0f;
163			float m_max = 1.0f;
164			for (uint32_t i = 0; i < 20; i++) {
165				float m = (m_min + m_max) / 2.0f;
166				float l = m - d;
167				float r = m + d;
168	
169				bm = -((am - 1) * l * l) / (r * r - 2 * r + l * l + 1);
170	
171				float l_actual = (left_inverse_piecewise_switch - bm) / am;
172				float r_actual = (right_inverse_piecewise_switch - bm) / am;
173				float m_actual = (l_actual + r_actual) / 2;
174	
175				if (m_actual > m) {
176					m_min = m;
177				} else {
178					m_max = m;
179				}
180			}
181	
182			float l = (left_inverse_piecewise_switch - bm) / am;
183			float r = (right_inverse_piecewise_switch - bm) / am;
184	
185			// Full linear case. Default construction covers this.
186			if ((l == 0.0f && r == 1.0f) || (am == 1.0f)) {
187				return;
188			}
189	
190			// write out solution
191			switch_left = l;
192			switch_right = r;
193			this->am = am;
194			al = (am - 1) / (r * r - 2 * r + l * l + 1);
195			bl = (am * (r * r - 2 * r + 1) + am * l * l + (2 - 2 * am) * l) / (r * r - 2 * r + l * l + 1);
196			cl = 0;
197			this->bm = bm = -((am - 1) * l * l) / (r * r - 2 * r + l * l + 1);
198			ar = -(am - 1) / (r * r - 2 * r + l * l + 1);
199			br = (am * (r * r + 1) - 2 * r + am * l * l) / (r * r - 2 * r + l * l + 1);
200			cr = -(am * r * r - r * r + (am - 1) * l * l) / (r * r - 2 * r + l * l + 1);
201	
202			inv_switch_left = am * switch_left + bm;
203			inv_switch_right = am * switch_right + bm;
204		}
205	
206		// left parabola: al * x^2 + bl * x + cl
207		float al = 0.0f, bl = 0.0f, cl = 0.0f;
208		// middle linear piece: am * x + bm.  am should give 1:1 pixel mapping between warped size and full size.
209		float am = 1.0f, bm = 0.0f;
210		// right parabola: al * x^2 + bl * x + cl
211		float ar = 0.0f, br = 0.0f, cr = 0.0f;
212	
213		// points where left and right switch over from quadratic to linear
214		float switch_left = 0.0f, switch_right = 1.0f;
215		// same, in inverted space
216		float inv_switch_left = 0.0f, inv_switch_right = 1.0f;
217	
218		NGP_HOST_DEVICE float warp(float x) const {
219			x = clamp(x, 0.0f, 1.0f);
220			if (x < switch_left) {
221				return al * x * x + bl * x + cl;
222			} else if (x > switch_right) {
223				return ar * x * x + br * x + cr;
224			} else {
225				return am * x + bm;
226			}
227		}
228	
229		NGP_HOST_DEVICE float unwarp(float y) const {
230			y = clamp(y, 0.0f, 1.0f);
231			if (y < inv_switch_left) {
232				return (sqrt(-4 * al * cl + 4 * al * y + bl * bl) - bl) / (2 * al);
